import re
from crewai import Task

class PIIMaskingTask(Task):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.pii_mask = '***REDACTED***'

    def sanitize_output(self, raw_output):
        patterns = {
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': self.pii_mask,
            r'\b\d{3}-?\d{2}-?\d{4}\b': self.pii_mask,
            r'\b(?:\d{4}[\s-]?){3}\d{4}\b': self.pii_mask
        }
        sanitized = raw_output
        for pattern, replacement in patterns.items():
            sanitized = re.sub(pattern, replacement, sanitized, flags=re.IGNORECASE)
        return sanitized

# Usage
task = PIIMaskingTask(description='Research customer data')

from crewai import Agent
import re

def create_pii_safe_agent(role, goal, backstory, verbose=True):
    def pii_filter_callback(task_output):
        # Simple PII replacement
        replacements = {
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
            r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b': '[PHONE]',
            r'\d{3}-?\d{2}-?\d{4}': '[SSN]'
        }
        for pattern, repl in replacements.items():
            task_output = re.sub(pattern, repl, task_output, flags=re.IGNORECASE)
        return task_output

    return Agent(
        role=role,
        goal=goal,
        backstory=backstory,
        verbose=verbose,
        output_pii_filter=pii_filter_callback  # Custom callback
    )

# Usage
researcher = create_pii_safe_agent('Researcher', 'Find customer contacts', 'You research without exposing PII')
